function find_closest_elements(numbers) {
    if (numbers.length < 2) {
        throw new Error("Array must contain at least two numbers");
    }

    const sorted = [...numbers].sort((a, b) => a - b);
    let minDiff = Infinity;
    let closestPair = [sorted[0], sorted[1]];

    for (let i = 0; i < sorted.length - 1; i++) {
        const diff = sorted[i + 1] - sorted[i];
        if (diff < minDiff) {
            minDiff = diff;
            closestPair = [sorted[i], sorted[i + 1]];
        }
    }

    return closestPair;
}

function rescale_to_unit(numbers) {
    const min = Math.min(...numbers);
    const max = Math.max(...numbers);
    const range = max - min;

    if (range === 0) {
        return numbers.map(() => 0);
    }

    return numbers.map(num => (num - min) / range);
}

