function modp(n, p) {
    if (p === 1) return 0;
    let result = 1n;
    let base = 2n;
    let exp = BigInt(n);
    const mod = BigInt(p);

    while (exp > 0n) {
        if (exp & 1n) {
            result = (result * base) % mod;
        }
        base = (base * base) % mod;
        exp >>= 1n;
    }

    return Number(result);
}

