function circular_shift(x, shift) {
    const s = String(Math.abs(x));
    const n = s.length;
    if (n === 0) return "";

    let effectiveShift = shift % n;

    if (shift > n) {
        return s.split('').reverse().join('');
    }

    if (effectiveShift === 0) {
        return s;
    }

    const splitIndex = n - effectiveShift;
    const rightPart = s.slice(splitIndex);
    const leftPart = s.slice(0, splitIndex);

    return rightPart + leftPart;
}

