                // Valid bracket sequence means every closing bracket matches an opening one before it.
                // Nesting means there exists at least one pair inside another pair.

                // If we have "[]]]]]]][[[[[]", can we pick a subsequence like "[[]]"?
                // The string has: [ ] ] ] ] ] ] ] [ [ [ [ [ ]
                // Indices of '[': 0, 8, 9, 10, 11, 12
                // Indices of ']': 1, 2, 3, 4, 5, 6, 7, 13
                // To form "[[]]", we need two '[' and two ']' in order: [ ... [ ... ] ... ]
                // We have plenty of '[' at the end. But do we have a matching structure?
                // If we pick index 0 ('['), then index 8 ('['), then index 13 (']'), then... wait, we need another ']' after index 13. There isn't one.
                // So we can't form "[[]]" using the last block.
                // What about using the first '[' and some later ones?
                // We need: [ (from early) ... [ (from late) ... ] (from late) ... ] (from late).
                // The only ']' after the second batch of '[' is at index 13.
                // So we can form "[]" using index 0 and 13? No, that's valid but not nested.
                // Can we form "[[]]"? We need two closing brackets after the second opening.
                // The only closing bracket after the second batch of openings is at 13.
                // So we can't close the inner pair and then the outer pair.
                // Thus, no nested valid subsequence exists.

                // Algorithm idea:
                // We need to find if there exist indices i < j < k < l such that s[i] = '[', s[j] = '[', s[k] = ']', s[l] = ']'
                // AND the subsequence formed by these (and potentially others) is valid.
                // Actually, if we just find "[[]]" as a subsequence, is it guaranteed to be valid?
                // Yes, because "[[]]" itself is a valid bracket sequence.
                // So the problem reduces to: Does the string contain "[[]]" as a subsequence?
                // Wait, is that sufficient?
                // If we have "[[]]", it's valid and nested.
                // Are there other valid nested sequences? Like "[[[]]]"? That contains "[[]]".
                // What about "[][[]]"? Contains "[[]]".
                // It seems any valid bracket sequence with nesting must contain "[[]]" as a subsequence.
                // Proof: If a valid sequence has depth >= 2, there is an opening bracket that has another opening bracket before its matching closing bracket.
                // Let the outer pair be at i and l. Inside, there is a pair j, k where i < j < k < l.
                // Then s[i]='[', s[j]='[', s[k]=']', s[l]=']'.
                // So yes, checking for "[[]]" as a subsequence is necessary and sufficient.

                // Let's verify with examples:
                // "[[]]" -> contains "[[]]" -> true.
                // "[]]]]]]][[[[[]" -> 
                //   Find first '[' at 0.
                //   Find next '[' after 0 -> at 8.
                //   Find next ']' after 8 -> at 13.
                //   Find next ']' after 13 -> None.
                //   So false. Correct.
                // "[][]" -> 
                //   First '[' at 0.
                //   Next '[' after 0 -> at 2.
                //   Next ']' after 2 -> at 3.
                //   Next ']' after 3 -> None.
                //   False. Correct.
                // "[]" -> False. Correct.
                // "[[][]]" -> 
                //   First '[' at 0.
                //   Next '[' at 1 (or 2). Let's pick 1.
                //   Next ']' after 1 -> at 2.
                //   Next ']' after 2 -> at 3 (or 5). Pick 3.
                //   Found "[[]]". True. Correct.
                // "[[]][[" -> 
                //   First '[' at 0.
                //   Next '[' at 1.
                //   Next ']' at 2.
                //   Next ']' at 3.
                //   Found. True. Correct.

                // So the logic is simply: check if "[[]]" is a subsequence.
            }
        }
    }

    // Reset and implement the subsequence check properly
    let target = "[[]]";
    let tIdx = 0;

    for (let i = 0; i < s.length && tIdx < target.length; i++) {
        if (s[i] === target[tIdx]) {
            tIdx++;
        }
    }

    return tIdx === target.length;
}

