function check_if_last_char_is_a_letter(txt) {
  if (!txt || txt.length === 0) return false;

  const lastChar = txt[txt.length - 1];

  // Check if the last character is an alphabetical letter
  if (!/[a-zA-Z]/.test(lastChar)) {
    return false;
  }

  // If the string ends with a space, the last char is not part of a word
  // But we already checked that the last char is a letter, so this case is handled above

  // Check if the character before the last one is a space or if it's the first character
  // This ensures the last letter is not part of a longer word
  const secondLastIndex = txt.length - 2;

  if (secondLastIndex < 0) {
    // String has only one character, which is a letter -> it's a word by itself
    return true;
  }

  const secondLastChar = txt[secondLastIndex];

  // If the character before the last is a space, then the last letter is a standalone word
  if (secondLastChar === ' ') {
    return true;
  }

  // If there's no space before the last letter, it's part of a longer word
  return false;
}

