function simplify(x, n) {
  const [xNum, xDen] = x.split('/').map(Number);
  const [nNum, nDen] = n.split('/').map(Number);

  // Calculate the product: (xNum * nNum) / (xDen * nDen)
  const numerator = xNum * nNum;
  const denominator = xDen * nDen;

  // Check if the result is a whole number
  return numerator % denominator === 0;
}

function order_by_points(nums) {
    const sumOfDigits = (n) => {
        let sum = 0;
        let num = Math.abs(n);
        if (num === 0) return 0;
        while (num > 0) {
            sum += num % 10;
            num = Math.floor(num / 10);
        }
        return sum;
    };

    const indexed = nums.map((num, index) => ({ num, index, points: sumOfDigits(num) }));

    indexed.sort((a, b) => {
        if (a.points !== b.points) {
            return a.points - b.points;
        }
        return a.index - b.index;
    });

    return indexed.map(item => item.num);
}

function specialFilter(nums) {
    let count = 0;
    const oddDigits = ['1', '3', '5', '7', '9'];

    for (const num of nums) {
        if (num <= 10) continue;

        const strNum = Math.abs(num).toString();
        const firstDigit = strNum[0];
        const lastDigit = strNum[strNum.length - 1];

        if (oddDigits.includes(firstDigit) && oddDigits.includes(lastDigit)) {
            count++;
        }
    }

    return count;
}

function get_max_triples(n) {
    if (n < 3) return 0;

    const a = [];
    for (let i = 1; i <= n; i++) {
        a.push(i * i - i + 1);
    }

    let count = 0;
    for (let i = 0; i < n - 2; i++) {
        for (let j = i + 1; j < n - 1; j++) {
            for (let k = j + 1; k < n; k++) {
                if ((a[i] + a[j] + a[k]) % 3 === 0) {
                    count++;
                }
            }
        }
    }

    return count;
}

