function do_algebra(operator, operand) {
    const tokens = [];
    for (let i = 0; i < operand.length; i++) {
        tokens.push(operand[i]);
        if (i < operator.length) {
            let op = operator[i];
            if (op === '//') {
                tokens.push('Math.floor');
                tokens.push('/');
            } else if (op === '**') {
                tokens.push('**');
            } else {
                tokens.push(op);
            }
        }
    }

    // Convert to a valid JS expression string
    let expr = '';
    for (let i = 0; i < tokens.length; i++) {
        if (tokens[i] === 'Math.floor') {
            expr += `Math.floor(${tokens[i + 1]} ${tokens[i + 2]} ${tokens[i + 3]})`;
            i += 3;
        } else {
            expr += tokens[i];
        }
    }

    return Function(`'use strict'; return (${expr});`)();
}

